36	fn split_once(s: &str, c: char) -> (&str, &str) {
37	    match s.find(c) {
38	        Some(index) => {
39	            let (l, r) = s.split_at(index);
40	            (l, &r[1..])
41	        }
42	        None => (s, ""),
43	    }
44	}
