100	/// Get the a `&str`-value iterator for a `&str`-key according to the parameters format.
101	pub fn values<'s>(s: &'s str, k: &str) -> impl DoubleEndedIterator<Item = &'s str> {
102	    match get(s, k) {
103	        Some(v) => v.split(VALUE_SEPARATOR),
