143	/// Same as [`insert`] but keys are sorted in alphabetical order.
144	pub fn insert_sort<'s>(s: &'s str, k: &'s str, v: &'s str) -> (String, Option<&'s str>) {
145	    let (iter, item) = _insert(iter(s), k, v);
146	    (from_iter(sort(iter)), item)
147	}
