149	/// Remove a key-value `(&str, &str)` pair from `s` preserving the insertion order.
150	pub fn remove<'s>(s: &'s str, k: &str) -> (String, Option<&'s str>) {
151	    let mut iter = iter(s);
152	    let item = iter.find(|(key, _)| *key == k).map(|(_, v)| v);
153	    let iter = iter.filter(|x| x.0 != k);
154	    (concat(iter), item)
155	}
