157	/// Returns `true` if all keys are sorted in alphabetical order
158	pub fn is_ordered(s: &str) -> bool {
159	    let mut prev = None;
160	    for (k, _) in iter(s) {
161	        match prev.take() {
162	            Some(p) if k < p => return false,
163	            _ => prev = Some(k),
164	        }
165	    }
166	    true
167	}
