178	fn concat_into<'s, I>(iter: I, into: &mut String)
179	where
180	    I: Iterator<Item = (&'s str, &'s str)>,
181	{
182	    let mut first = true;
183	    for (k, v) in iter.filter(|(k, _)| !k.is_empty()) {
184	        if !first {
185	            into.push(LIST_SEPARATOR);
186	        }
187	        into.push_str(k);
188	        if !v.is_empty() {
189	            into.push(FIELD_SEPARATOR);
190	            into.push_str(v);
191	        }
192	        first = false;
193	    }
194	}
