235	///
236	/// let a = "a=1;b=2;c=3|4|5;d=6";
237	/// let p = Parameters::from(a);
238	///
239	/// // Retrieve values
240	/// assert!(!p.is_empty());
241	/// assert_eq!(p.get("a").unwrap(), "1");
