243	/// assert_eq!(p.get("c").unwrap(), "3|4|5");
244	/// assert_eq!(p.get("d").unwrap(), "6");
245	/// assert_eq!(p.values("c").collect::<Vec<&str>>(), vec!["3", "4", "5"]);
