49	
50	/// The reply consolidation strategy to apply to replies to a [`get`](crate::Session::get).
51	///
52	/// By default, the consolidation strategy is [`QueryConsolidation::AUTO`], which lets the implementation
53	/// choose the best strategy depending on the query parameters and the number of responders.
54	/// Other strategies can be selected by using
55	/// a specific [`ConsolidationMode`] as a parameter of the
56	/// [`QuerierBuilder::consolidation`](crate::query::QuerierBuilder::consolidation)
57	/// or [`SessionGetBuilder::consolidation`](crate::session::SessionGetBuilder::consolidation)
58	/// methods.
59	///
60	/// See the documentation of [`ConsolidationMode`] for more details about each strategy.
61	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
62	pub struct QueryConsolidation {
63	    pub(crate) mode: ConsolidationMode,
64	}
65	
66	impl QueryConsolidation {
67	    pub const DEFAULT: Self = Self::AUTO;
68	    /// Automatic query consolidation strategy selection.
69	    pub const AUTO: Self = Self {
70	        mode: ConsolidationMode::Auto,
71	    };
72	
73	    pub(crate) const fn from_mode(mode: ConsolidationMode) -> Self {
74	        Self { mode }
75	    }
