95	/// An error reply variant returned by [`Querier::get`](crate::query::Querier::get)
96	/// or [`Session::get`](crate::Session::get) in [`Reply`]
97	///
98	/// The `ReplyError` contains the payload with the error information (message or some structured data)
99	/// and the encoding of this payload.
100	#[derive(Clone, Debug, PartialEq, Eq, Default)]
101	pub struct ReplyError {
102	    pub(crate) payload: ZBytes,
103	    pub(crate) encoding: Encoding,
104	}
105	
106	impl ReplyError {
107	    pub(crate) fn new(payload: impl Into<ZBytes>, encoding: Encoding) -> Self {
108	        Self {
109	            payload: payload.into(),
110	            encoding,
111	        }
112	    }
113	
114	    /// Gets the payload of this ReplyError.
115	    #[inline]
116	    pub fn payload(&self) -> &ZBytes {
117	        &self.payload
118	    }
119	
120	    /// Gets the mutable payload of this ReplyError.
121	    #[inline]
122	    pub fn payload_mut(&mut self) -> &mut ZBytes {
123	        &mut self.payload
124	    }
125	
126	    /// Gets the encoding of this ReplyError.
127	    #[inline]
128	    pub fn encoding(&self) -> &Encoding {
129	        &self.encoding
130	    }
131	
132	    /// Constructs an uninitialized empty ReplyError.
133	    #[zenoh_macros::internal]
134	    pub fn empty() -> Self {
135	        ReplyError {
136	            payload: ZBytes::new(),
137	            encoding: Encoding::default(),
138	        }
139	    }
140	}
141	
142	impl Display for ReplyError {
143	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
144	        write!(
145	            f,
146	            "query returned an error with a {}-byte payload and encoding {}",
147	            self.payload.len(),
148	            self.encoding
149	        )
150	    }
151	}
152	
153	impl Error for ReplyError {}
154	
155	/// An answer received from a [`Queryable`](crate::query::Queryable).
156	///
157	/// The `Reply` contains the result of the request to a [`Queryable`](crate::query::Queryable) by
158	/// [`Session::get`](crate::Session::get) or [`Querier::get`](crate::query::Querier::get).
159	///
160	/// It may be either a successful result with a [`Sample`](crate::sample::Sample) or an error with a [`ReplyError`].
161	/// The method [`Reply::result`] is provided to access the result.
162	#[non_exhaustive]
163	#[derive(Clone, Debug)]
164	pub struct Reply {
165	    pub(crate) result: Result<Sample, ReplyError>,
166	    #[cfg(feature = "unstable")]
167	    pub(crate) replier_id: Option<EntityGlobalIdProto>,
168	}
169	
170	impl Reply {
171	    /// Gets a borrowed result of this `Reply`. Use [`Reply::into_result`] to take ownership of the result.
172	    pub fn result(&self) -> Result<&Sample, &ReplyError> {
173	        self.result.as_ref()
174	    }
175	
176	    /// Gets a mutable borrowed result of this `Reply`. Use [`Reply::into_result`] to take ownership of the result.
177	    pub fn result_mut(&mut self) -> Result<&mut Sample, &mut ReplyError> {
178	        self.result.as_mut()
179	    }
180	
181	    /// Converts this `Reply` into its result. Use [`Reply::result`] if you don't want to take ownership.
182	    pub fn into_result(self) -> Result<Sample, ReplyError> {
183	        self.result
184	    }
185	
186	    #[zenoh_macros::unstable]
187	    /// Gets the ID of the zenoh instance that answered this reply.
188	    pub fn replier_id(&self) -> Option<EntityGlobalId> {
189	        self.replier_id.map(Into::into)
190	    }
191	
192	    /// Constructs an uninitialized empty Reply.
193	    #[zenoh_macros::internal]
194	    pub fn empty() -> Self {
195	        Reply {
196	            result: Ok(Sample::empty()),
197	            #[cfg(feature = "unstable")]
198	            replier_id: None,
199	        }
200	    }
201	}
202	
203	impl CallbackParameter for Reply {
204	    type Message<'a> = Self;
205	
206	    fn from_message(msg: Self::Message<'_>) -> Self {
207	        msg
208	    }
209	}
