222	    pub(crate) nb_final: usize,
223	    pub(crate) key_expr: OwnedKeyExpr,
224	    pub(crate) parameters: Parameters<'static>,
225	    pub(crate) reception_mode: ConsolidationMode,
226	    pub(crate) replies: Option<HashMap<OwnedKeyExpr, Reply>>,
227	    pub(crate) callback: Callback<Reply>,
228	    pub(crate) querier_id: Option<Id>,
229	}
230	/// The kinds of accepted query replies.
231	///
232	/// The [`Queryable`](crate::query::Queryable) may serve glob-like key expressions.
233	/// E.g., the queryable may be declared with the key expression `foo/*`.
234	/// At the same time, it may send replies with more specific key expressions, e.g., `foo/bar` or `foo/baz`.
235	/// This may cause a situation when the queryable receives a query with the key expression `foo/bar`
236	/// and replies to it with the key expression `foo/baz`.
237	///
238	/// By default, this behavior is not allowed. Calling [`Query::reply`](crate::query::Query::reply) on
239	/// a query for `foo/bar` with key expression `foo/baz` will result in an error on the sending side.
240	///
241	/// But if the query is sent with the [`ReplyKeyExpr::Any`] parameter in [`accept_replies`](crate::session::SessionGetBuilder::accept_replies) (for
242	/// [`Session::get`](crate::session::Session::get) or
243	/// [`accept_replies`](crate::query::QuerierBuilder::accept_replies) for
244	/// [`Querier::get`](crate::query::Querier::get))
245	/// then the reply with a disjoint key expression will be accepted for this query.
246	/// Currently, this information is passed in the [`Selector`](crate::api::selector::Selector) parameters as the `_anyke` parameter.
247	///
248	/// The [`Queryable`](crate::query::Queryable) may check this parameter with
249	/// [`Query::accepts_replies`](crate::query::Query::accepts_replies).
250	#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default, Deserialize)]
